/// GET v1/photos
/// Lists all the Photos that belong to the user. &gt; Note: Recently created photos that are still being indexed are not returned in the response.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `streetviewpublish_photos_list_execute()` to send, or `streetviewpublish_photos_list` for simplest API.

pub fn streetviewpublish_photos_list_builder(
    client: &SimpleHttpClient,
    filter: Option<&str>,
    languageCode: Option<&str>,
    pageSize: Option<i32>,
    pageToken: Option<&str>,
    view: Option<&str>,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!("https://api.example.comv1/photos",);

    // Build request
    client
        .get(&url)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))
        .query(
            "filter",
            filter
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "languageCode",
            languageCode
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "pageSize",
            pageSize
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "pageToken",
            pageToken
                .as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
        .query(
            "view",
            view.as_ref()
                .map(|s| s.to_string())
                .unwrap_or_default()
                .as_str(),
        )
}

